class AllOne {
private:
    unordered_map<string, int> keyCount;
    unordered_map<int, list<string>> countKeys;
    list<string>::iterator maxIt;
    list<string>::iterator minIt;

public:
    AllOne() : maxIt(), minIt() {}

    void inc(string key) {
        int count = keyCount[key];
        if (count > 0) {
            countKeys[count].remove(key);
            if (countKeys[count].empty() && count == 1) {
                minIt = countKeys.begin()->second.end();
            }
            if (countKeys[count].empty() && count == *maxIt) {
                maxIt = countKeys.begin()->second.begin();
            }
        }
        keyCount[key]++;
        count = keyCount[key];
        countKeys[count].push_back(key);
        if (count == 1) {
            minIt = countKeys[count].end();
            --minIt;
        }
        if (maxIt == countKeys.end() || count > *maxIt) {
            maxIt = countKeys[count].begin();
        }
    }

    void dec(string key) {
        int count = keyCount[key];
        countKeys[count].remove(key);
        if (countKeys[count].empty() && count == *minIt) {
            if (countKeys.empty()) {
                minIt = list<string>::iterator();
                maxIt = list<string>::iterator();
            } else {
                minIt = countKeys.begin()->second.begin();
            }
        }
        if (countKeys[count].empty() && count == *maxIt) {
            maxIt = countKeys.begin()->second.begin();
        }
        keyCount[key]--;
        count = keyCount[key];
        countKeys[count].push_back(key);
        if (maxIt == countKeys.end() || count >= *maxIt) {
            maxIt = countKeys[count].end();
            --maxIt;
        }
        if (minIt == countKeys.end() || count <= *minIt) {
            minIt = countKeys[count].begin();
        }
    }

    string getMaxKey() {
        return maxIt == countKeys.end() ? "" : *maxIt;
    }

    string getMinKey() {
        return minIt == countKeys.end() ? "" : *minIt;
    }
};
```
